const raw = $input.item.json.choices[0].message.content;
const refusalMsg = $input.item.json.choices[0].message.refusal;
if (raw === null || refusalMsg) {
  const kw = $('Tomar Primera Keyword').first().json.keyword || 'desconocida';
  throw new Error('OpenAI rehusó la keyword "' + kw + '". Refusal: ' + (refusalMsg || 'sin mensaje') + '. Reescribe la keyword a wording más neutral.');
}
let article;
try {
  article = JSON.parse(raw);
} catch(e) {
  throw new Error('JSON parse error: ' + raw.substring(0, 200));
}

function strip4Byte(str) {
  if (typeof str !== 'string') return str;
  return str.replace(/[\u{10000}-\u{10FFFF}]/gu, '');
}

function scrubAIWatermarks(str) {
  if (typeof str !== 'string' || !str) return str;
  str = str.replace(/\p{Cf}/gu, '');
  str = str.replace(/\s+[—–]\s+([A-ZÁÉÍÓÚÑ][a-záéíóúñ]+)/g, ', $1');
  str = str.replace(/\s+[—–]\s+(?=[A-ZÁÉÍÓÚÑ])/g, '. ');
  str = str.replace(/\s*[—–]\s*/g, ', ');
  str = str.replace(/[ \t]+/g, ' ');
  str = str.replace(/ ([,.!?;:])/g, '$1');
  str = str.replace(/\n{3,}/g, '\n\n');
  return str;
}

function capitalizarPrimera(str) {
  if (!str) return '';
  return str.replace(/[a-záéíóúüñA-ZÁÉÍÓÚÜÑ]/, c => c.toUpperCase());
}

function aplicarInterrogacion(str) {
  if (!str) return '';
  const trimmed = str.trim();
  const startsQ = /^(qué|que|cuánto|cuanto|cómo|como|cuál|cual|por qué|por que|cuándo|cuando|dónde|donde|quién|quien|es |son |puede|pueden|debo|debería|sirve|funciona|existe|hay)/i.test(trimmed);
  if (startsQ && !trimmed.startsWith('¿')) {
    return '¿' + trimmed + (trimmed.endsWith('?') ? '' : '?');
  }
  return trimmed;
}

function limpiarFAQ(html) {
  return html
    .replace(/<blockquote[^>]*>/gi, '')
    .replace(/<\/blockquote>/gi, '')
    .replace(/^(&gt;|>)+\s*/gm, '')
    .replace(/<p>\s*(&gt;|>)+\s*/g, '<p>');
}

function capitalizarHeadings(html) {
  return html.replace(/(<h[2-4][^>]*>)([\s\S]*?)(<\/h[2-4]>)/gi, (m, open, content, close) => {
    let fixed = content.replace(/[a-záéíóúüñ]/i, c => c.toUpperCase());
    fixed = fixed.replace(/:\s+([a-záéíóúüñ])/gi, (_, l) => ': ' + l.toUpperCase());
    fixed = aplicarInterrogacion(fixed);
    return open + fixed + close;
  });
}

function slugify(str) {
  return str.toLowerCase()
    .normalize('NFD').replace(/[̀-ͯ]/g, '')
    .replace(/[^a-z0-9\s-]/g, '').trim()
    .replace(/\s+/g, '-').replace(/-+/g, '-');
}

function truncarMeta(str, max) {
  if (!str || str.length <= max) return str;
  const cut = str.substring(0, max);
  const lastSpace = cut.lastIndexOf(' ');
  return lastSpace > max - 20 ? cut.substring(0, lastSpace) : cut;
}

function normalizarTexto(str) {
  return (str || '').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '').trim();
}

function buildFAQHtml(items) {
  if (!items || items.length === 0) return '';
  const rows = items.map(item => {
    const q = scrubAIWatermarks(aplicarInterrogacion(capitalizarPrimera((item.question || '').trim())));
    const a = scrubAIWatermarks((item.answer || '').trim());
    return '<h3>' + q + '</h3>\n<p>' + a + '</p>';
  }).join('\n');
  return '<h2>Preguntas frecuentes</h2>\n' + rows;
}

function buildFAQJsonLD(items) {
  if (!items || items.length === 0) return '';
  const entities = items.map(item => ({
    '@type': 'Question',
    'name': scrubAIWatermarks(aplicarInterrogacion(capitalizarPrimera((item.question || '').trim()))),
    'acceptedAnswer': {'@type': 'Answer', 'text': scrubAIWatermarks((item.answer || '').trim())}
  }));
  const schema = {'@context': 'https://schema.org', '@type': 'FAQPage', 'mainEntity': entities};
  return '<script type="application/ld+json">\n' + JSON.stringify(schema) + '\n</script>';
}

function buildFuentesHtml(items) {
  if (!items || items.length === 0) return '';
  const valid = items.filter(it => it && it.url && it.nombre);
  if (valid.length === 0) return '';
  const stripInvisibles = (s) => {
    if (typeof s !== 'string') return '';
    return s.replace(/[​-‍﻿⁠­ ]/g, '').replace(/\p{Cf}/gu, '').trim();
  };
  const rows = valid.map(it => {
    const nombre = stripInvisibles(String(it.nombre || ''));
    const url = stripInvisibles(String(it.url || ''));
    const desc = stripInvisibles(String(it.descripcion || ''));
    const descPart = desc ? ' — ' + desc : '';
    return '<li><a href="' + url + '" rel="nofollow noopener" target="_blank">' + nombre + '</a>' + descPart + '</li>';
  }).join('\n');
  return '<section class="fuentes-consultadas">\n<h2>Fuentes consultadas</h2>\n<p>El contenido de este artículo se apoya en publicaciones de organizaciones veterinarias autoritativas. Te invitamos a consultarlas para profundizar:</p>\n<ul>\n' + rows + '\n</ul>\n</section>';
}

function buildSpeakableJsonLD(entities) {
  const schema = {
    '@context': 'https://schema.org',
    '@type': 'WebPage',
    'speakable': {
      '@type': 'SpeakableSpecification',
      'cssSelector': ['.respuesta-directa', '.key-takeaways']
    }
  };
  const valid = (entities || []).filter(e => e && e.nombre && e.wikipedia_url && /^https:\/\/[a-z]{2,3}\.wikipedia\.org\//.test(e.wikipedia_url));
  if (valid.length > 0) {
    schema.mentions = valid.map(e => ({
      '@type': 'Thing',
      'name': scrubAIWatermarks(String(e.nombre).trim()),
      'sameAs': String(e.wikipedia_url).trim()
    }));
  }
  return '<script type="application/ld+json">\n' + JSON.stringify(schema) + '\n</script>';
}

function buildHowToJsonLD(steps, name) {
  if (!steps || !Array.isArray(steps) || steps.length < 4) return '';
  const valid = steps.filter(s => s && s.name && s.text);
  if (valid.length < 4) return '';
  const stepsList = valid.map((s, i) => ({
    '@type': 'HowToStep',
    'position': i + 1,
    'name': scrubAIWatermarks(String(s.name).trim()),
    'text': scrubAIWatermarks(String(s.text).trim())
  }));
  const schema = {
    '@context': 'https://schema.org',
    '@type': 'HowTo',
    'name': scrubAIWatermarks(String(name || '').trim()),
    'step': stepsList
  };
  return '<script type="application/ld+json">\n' + JSON.stringify(schema) + '\n</script>';
}

const categoriaMap = {
  'salud': 41, 'salud canina': 41, 'salud del perro': 41,
  'alimentacion': 42, 'alimentacion canina': 42, 'alimentacion del perro': 42,
  'razas': 45, 'razas de perros': 45,
  'educacion y comportamiento': 43, 'comportamiento': 43, 'comportamiento y adiestramiento': 43, 'educacion': 43, 'el mundo del perro': 43,
  'noticias': 157
};

function inferirCategoria(raw) {
  const n = normalizarTexto(raw);
  if (/salud|enfermed|veterinari|medicin|esteriliz|vacun|parasit|cushing|hepatitis|diarrea|rabia/.test(n)) return 41;
  if (/aliment|comida|nutri|dieta|croqueta|pienso/.test(n))               return 42;
  if (/raza|golden|labrador|pastor|bulldog|husky|chihuahua|poodle|border collie|criollo/.test(n)) return 45;
  if (/comportam|adiestr|educac|ansiedad|socializ|ladr|morder|conducta/.test(n)) return 43;
  if (/noticia|novedad|actual/.test(n))                                   return 157;
  // Fallback al hub del Sheet (col R) — más fiable que retornar default fijo
  try {
    const hub = ($('Leer Keywords Aprobadas').first().json.hub || '').toLowerCase();
    if (hub.includes('salud')) return 41;
    if (hub.includes('aliment')) return 42;
    if (hub.includes('raza')) return 45;
    if (hub.includes('comport')) return 43;
  } catch(e) {}
  return 41; // último fallback: Salud (NUNCA volver a 'Sin categoría')
}

const categoriaNorm = normalizarTexto(article.categoria);
const categoriaId   = categoriaMap[categoriaNorm] || inferirCategoria(article.categoria);
const keyword       = $('Leer Keywords Aprobadas').item.json.keyword || '';
const tituloLimpio  = aplicarInterrogacion(capitalizarPrimera(article.titulo_seo || ''));

let bodyHtml = strip4Byte((article.body_html || '').replace(/<h1[^>]*>[\s\S]*?<\/h1>/gi, '').trim());
bodyHtml = limpiarFAQ(bodyHtml);
bodyHtml = capitalizarHeadings(bodyHtml);

// ====== Inyecta respuesta_directa como PRIMER párrafo (AI Search optimization) ======
const respuestaDirecta = (article.respuesta_directa || '').trim();
if (respuestaDirecta) {
  bodyHtml = '<p class="respuesta-directa">' + respuestaDirecta + '</p>\n\n' + bodyHtml;
}

// ====== Inyecta key_takeaways como blockquote antes del primer H2 (Featured Snippet) ======
const takeaways = (article.key_takeaways || []).filter(t => t && String(t).trim());
if (takeaways.length >= 3) {
  const items = takeaways.map(t => '<li>' + String(t).trim() + '</li>').join('\n');
  const takeawaysHtml = '<blockquote class="key-takeaways">\n<p><strong>Conclusiones rápidas</strong></p>\n<ul>\n' + items + '\n</ul>\n</blockquote>';
  const firstH2 = bodyHtml.search(/<h2[^>]*>/i);
  if (firstH2 > 0) {
    bodyHtml = bodyHtml.slice(0, firstH2) + takeawaysHtml + '\n\n' + bodyHtml.slice(firstH2);
  } else {
    bodyHtml = takeawaysHtml + '\n\n' + bodyHtml;
  }
}

const faqItems = article.faq_items || [];
const faqHtml  = buildFAQHtml(faqItems);
const faqJsonLD = buildFAQJsonLD(faqItems);
if (faqHtml)   bodyHtml += '\n' + faqHtml;

// SCRUB sobre body+takeaways+FAQ (antes de añadir fuentes que usan em-dashes literales como separador)
bodyHtml = scrubAIWatermarks(bodyHtml);

// Append bloque de Fuentes consultadas (valores pre-scrubbed dentro de buildFuentesHtml; em-dashes intencionales)
const fuentesHtml = buildFuentesHtml(article.fuentes_consultadas || []);
if (fuentesHtml) bodyHtml += '\n' + fuentesHtml;

if (faqJsonLD) bodyHtml += '\n' + faqJsonLD;

// AEO: WebPage schema con Speakable (asistentes de voz) + mentions (Knowledge Graph signal vía Wikipedia sameAs)
bodyHtml += '\n' + buildSpeakableJsonLD(article.entities || []);

// HowTo schema (solo si GPT identificó la keyword como procedural y dio >= 4 pasos)
const howToHtml = buildHowToJsonLD(article.howto_steps || [], tituloLimpio);
if (howToHtml) bodyHtml += '\n' + howToHtml;

const metaDesc = scrubAIWatermarks(truncarMeta(article.meta_description || '', 145));

const wpPayload = {
  title:      scrubAIWatermarks(strip4Byte(tituloLimpio)),
  slug:       slugify(keyword),
  content:    bodyHtml,
  excerpt:    scrubAIWatermarks(strip4Byte(metaDesc)),
  status:     'publish',
  categories: [categoriaId],
  meta: {
    '_yoast_wpseo_title':    scrubAIWatermarks(strip4Byte(truncarMeta(article.seo_title || tituloLimpio, 60))),
    '_yoast_wpseo_metadesc': scrubAIWatermarks(strip4Byte(metaDesc)),
    '_yoast_wpseo_focuskw':  keyword
  }
};

const basePrompt = article.prompt_imagen || 'Realistic photo of a happy tabby cat, 85mm lens, golden hour lighting';
const nanoPayload = {
  contents: [{ parts: [{ text: basePrompt + '. Wide landscape format, 16:9 aspect ratio, blog header image.' }] }],
  generationConfig: {
    responseModalities: ['IMAGE'],
    candidateCount: 1,
    imageConfig: { aspectRatio: '16:9', imageSize: '1K' }
  }
};

return [{
  json: {
    titulo_seo:     scrubAIWatermarks(tituloLimpio),
    categoria_raw:  article.categoria || '',
    categoria_id:   categoriaId,
    tags_list:      article.tags || [],
    slug:           slugify(keyword),
    wordcount:      (bodyHtml.replace(/<[^>]*>/g, ' ').match(/\S+/g) || []).length,
    wp_body_json:   JSON.stringify(wpPayload),
    nano_body_json: JSON.stringify(nanoPayload)
  }
}];

const candidates = $input.item.json.candidates || [];
if (!candidates.length) throw new Error('nano banana: no candidates in response');

const finishReason = candidates[0].finishReason;
if (finishReason && finishReason !== 'STOP') {
  throw new Error('nano banana: Gemini rechazó generar imagen (finishReason=' + finishReason + '). Posible filtro de seguridad o límite del modelo. Re-aprueba la kw para reintentar.');
}

const content = candidates[0].content;
if (!content || !content.parts) {
  throw new Error('nano banana: respuesta sin content.parts. Gemini probablemente rechazó la generación. Re-aprueba la kw para reintentar.');
}

const parts = content.parts || [];
const imagePart = parts.find(p => p.inlineData);
if (!imagePart) throw new Error('nano banana: no inlineData in response parts');

const base64 = imagePart.inlineData.data;
const mimeType = imagePart.inlineData.mimeType || 'image/png';
const ext = mimeType.includes('jpeg') ? 'jpg' : 'png';

const keyword = $('Leer Keywords Aprobadas').item.json.keyword;
const filename = keyword
  .toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '')
  .substring(0, 60) + '.' + ext;

const buffer = Buffer.from(base64, 'base64');
const binaryData = await this.helpers.prepareBinaryData(buffer, filename, mimeType);

return [{
  json: {
    image_filename: filename,
    image_mime_type: mimeType,
    titulo_seo: $('Parsear JSON articulo').item.json.titulo_seo,
    wp_body_json: $('Parsear JSON articulo').item.json.wp_body_json
  },
  binary: { image_data: binaryData }
}];

const mediaId = $input.item.json.id;
if (!mediaId) throw new Error('WP Media upload: no id returned');

const wpBodyStr = $('Parsear JSON articulo').item.json.wp_body_json;
const wpBody = JSON.parse(wpBodyStr);
wpBody.featured_media = mediaId;

return [{
  json: {
    wp_body_json: JSON.stringify(wpBody)
  }
}];

// v2 (2026-05-05): threshold kw 0.35 + slug similarity 0.60
const currentKeyword = $('Leer Keywords Aprobadas').first().json.keyword || '';
const allItems = $input.all();

const publishedPosts = allItems
  .filter(i => i.json && i.json.keyword && i.json.url_post)
  .map(i => ({ keyword: i.json.keyword, url: i.json.url_post }));

const posts_contexto = publishedPosts.length > 0
  ? 'Posts publicados en Bigotes Caninos (' + publishedPosts.length + ' artículos):\n'
    + publishedPosts.map(p => '- ' + p.keyword + ' → ' + p.url).join('\n')
  : 'No hay artículos publicados aún.';

function normalizar(str) {
  return (str || '').toLowerCase().normalize('NFD')
    .replace(/[̀-ͯ]/g, '')
    .replace(/[^a-z0-9\s-]/g, ' ')
    .trim();
}

const stopWords = new Set([
  'de','la','el','en','y','a','los','las','un','una','para','con','del','que','mi','tu','su','es',
  'se','no','al','lo','les','por','como','mas','o','u','sus','mis','tus','le','vs','sobre','entre',
  'ya','muy','sin','pero','si','ser','ir','ver','dar','hay','son','tan','sea','sean','guia','completa'
]);

function stem(w) {
  // Diminutivos: perrito/perrita/perritos/perritas → perro/perra
  w = w.replace(/it([oa])s?$/, '$1');
  // Plurales: quitar 's' final si la palabra es lo suficientemente larga
  if (w.length > 4 && w.endsWith('s')) w = w.slice(0, -1);
  return w;
}

function palabras(str) {
  return normalizar(str).split(/[\s-]+/)
    .filter(w => !stopWords.has(w) && w.length > 2)
    .map(stem);
}

function slugFromUrl(url) {
  const m = (url || '').match(/\/([^\/]+)\/?$/);
  return m ? m[1] : '';
}

function slugifyKw(str) {
  return normalizar(str).replace(/\s+/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
}

function jaccard(a, b) {
  if (a.size === 0 || b.size === 0) return 0;
  const inter = [...a].filter(w => b.has(w)).length;
  const uni   = new Set([...a, ...b]).size;
  return uni > 0 ? inter / uni : 0;
}

const currentKwSet    = new Set(palabras(currentKeyword));
const currentSlug     = slugifyKw(currentKeyword);
const currentSlugSet  = new Set(palabras(currentSlug));

let cannibalism = false, similar_keyword = '', similar_url = '', similarity_pct = 0, match_reason = '';

const KW_THRESHOLD   = 0.35;
const SLUG_THRESHOLD = 0.60;

for (const post of publishedPosts) {
  const postKwSet   = new Set(palabras(post.keyword));
  const postSlug    = slugFromUrl(post.url);
  const postSlugSet = new Set(palabras(postSlug));

  const kwSim   = jaccard(currentKwSet, postKwSet);
  const slugSim = jaccard(currentSlugSet, postSlugSet);

  let bestForThisPost = 0;
  let reasonForThisPost = '';
  if (kwSim >= KW_THRESHOLD) {
    bestForThisPost = Math.round(kwSim * 100);
    reasonForThisPost = 'kw_' + bestForThisPost + 'pct';
  }
  if (slugSim >= SLUG_THRESHOLD && Math.round(slugSim * 100) > bestForThisPost) {
    bestForThisPost = Math.round(slugSim * 100);
    reasonForThisPost = 'slug_' + bestForThisPost + 'pct';
  }
  if (bestForThisPost > similarity_pct) {
    cannibalism     = true;
    similar_keyword = post.keyword;
    similar_url     = post.url;
    similarity_pct  = bestForThisPost;
    match_reason    = reasonForThisPost;
  }
}

return [{ json: {
  posts_contexto, cannibalism,
  similar_keyword, similar_url, similarity_pct, match_reason,
  current_keyword: currentKeyword
} }];

