const tagNames = $("Parsear JSON articulo").first().json.tags_list || [];
const postId   = $("Publicar en WordPress").first().json.id;
if (!tagNames.length || !postId) return [];
return tagNames
  .filter(t => typeof t === "string" && t.trim())
  .map(tagName => ({
    json: {
      tagName: tagName.trim(),
      tagBody: JSON.stringify({ name: tagName.trim() }),
      postId
    }
  }));

const items = $input.all();
const tagIds = [];
for (const item of items) {
  const r = item.json;
  const id = r.id ?? r.data?.term_id;
  if (id) tagIds.push(Number(id));
}
const postId = $("Publicar en WordPress").first().json.id;
const patchBody = JSON.stringify({ tags: tagIds });
return [{ json: { tagIds, postId, patchBody } }];

const items = $input.all();
if (!items.length) return [];

// Prioriza keyword estacional (tiene fecha_objetivo)
const seasonal = items.find(item => (item.json.fecha_objetivo || '').trim());
if (seasonal) return [seasonal]; // Estacional: publica cualquier día

// Manual override: cualquier ejecución que NO sea el cron automático bypass el filtro de día
// Modes posibles: 'trigger' (cron), 'test' (Execute Workflow UI), 'manual', 'cli', 'webhook', 'integrated'
if ($execution?.mode !== 'trigger') return [items[0]];

// Cron automático: solo martes/jueves/sábado en Colombia (UTC-5)
const now = new Date();
const colombiaDate = new Date(now.getTime() + (-5 * 60 - now.getTimezoneOffset()) * 60000);
const dow = colombiaDate.getDay(); // 0=Dom, 1=Lun, 2=Mar, 3=Mié, 4=Jue, 5=Vie, 6=Sáb
if ([2, 4, 6].includes(dow)) return [items[0]];

// No es martes/jueves/sábado y no hay estacional urgente → termina silenciosamente
return [];

const items = $input.all();
const today = new Date();
today.setHours(0,0,0,0);
const windowEnd = new Date(today);
windowEnd.setDate(windowEnd.getDate() + 14);
const urgent = items.filter(item => {
  const fecha = (item.json.fecha_objetivo || '').trim();
  if (!fecha) return false;
  const target = new Date(fecha);
  return target >= today && target <= windowEnd;
});
if (!urgent.length) return [{ json: { found: false } }];
urgent.sort((a,b) => new Date(a.json.fecha_objetivo) - new Date(b.json.fecha_objetivo));
return [{ json: { found: true, ...urgent[0].json } }];

// Quality Gate — puntua el artículo 0-100 antes de publicar.
// Si score < 70, lanza Error → Error Trigger marca Sheet 'Error' + Telegram alert.

const data = $input.item.json;
const wpBody = JSON.parse(data.wp_body_json);
const keyword = $('Leer Keywords Aprobadas').item.json.keyword || '';

// Texto plano del body para análisis
const bodyText = wpBody.content
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const wordCount = bodyText.split(/\s+/).filter(w => w.length > 0).length;

const checks = {};
const breakdown = [];

function reEscape(s) { return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); }

// 1. Word count >= 1800 (10 pts)
checks.wordCount = wordCount >= 1800 ? 10 : Math.max(0, Math.round((wordCount / 1800) * 10));
breakdown.push(`Pálabras: ${wordCount}/1800 → ${checks.wordCount}/10`);

// 2. H2 count 4-7 (10 pts)
const h2Count = (wpBody.content.match(/<h2[^>]*>/gi) || []).length;
checks.h2Count = (h2Count >= 4 && h2Count <= 8) ? 10 : (h2Count >= 3 ? 6 : 2);
breakdown.push(`H2: ${h2Count} (target 4-7) → ${checks.h2Count}/10`);

// 3. Keyword en primeros 200 chars (10 pts)
const kwLower = keyword.toLowerCase();
const first200 = bodyText.substring(0, 200).toLowerCase();
checks.keywordIntro = first200.includes(kwLower) ? 10 : 0;
breakdown.push(`Keyword en primeros 200 chars: ${checks.keywordIntro === 10 ? 'YES' : 'NO'} → ${checks.keywordIntro}/10`);

// 4. Density 0.5-2% (10 pts)
const kwOcc = (bodyText.toLowerCase().match(new RegExp(reEscape(kwLower), 'g')) || []).length;
const density = wordCount > 0 ? kwOcc / wordCount : 0;
checks.density = (density >= 0.005 && density <= 0.02) ? 10 : (density > 0 && density <= 0.03) ? 5 : 0;
breakdown.push(`Density: ${(density*100).toFixed(2)}% (${kwOcc}/${wordCount}) → ${checks.density}/10`);

// 5. Enlaces internos >= 2 (5 pts)
const internalLinks = (wpBody.content.match(/href="https?:\/\/bigotescaninos\.com\/[^"#]+"/g) || []).length;
checks.internalLinks = internalLinks >= 2 ? 5 : (internalLinks * 2);
breakdown.push(`Internal links: ${internalLinks}/2 → ${checks.internalLinks}/5`);

// 6. Enlace externo nofollow >= 1 (5 pts)
const externalLinks = (wpBody.content.match(/href="https?:\/\/(?!bigotescaninos\.com)[^"]+"[^>]*rel="[^"]*nofollow/gi) || []).length;
checks.externalLinks = externalLinks >= 1 ? 5 : 0;
breakdown.push(`External nofollow: ${externalLinks}/1 → ${checks.externalLinks}/5`);

// 7. Meta title 50-60 (5 pts)
const metaTitleLen = (wpBody.meta._yoast_wpseo_title || '').length;
checks.metaTitle = (metaTitleLen >= 50 && metaTitleLen <= 60) ? 5 : 0;
breakdown.push(`SEO title: ${metaTitleLen} chars (50-60) → ${checks.metaTitle}/5`);

// 8. Meta description 130-145 (5 pts)
const metaDescLen = (wpBody.meta._yoast_wpseo_metadesc || '').length;
checks.metaDesc = (metaDescLen >= 130 && metaDescLen <= 145) ? 5 : 0;
breakdown.push(`Meta desc: ${metaDescLen} chars (130-145) → ${checks.metaDesc}/5`);

// 9. respuesta_directa: primer <p> con 80-320 chars (5 pts)
const firstPMatch = wpBody.content.match(/^<p[^>]*>([\s\S]*?)<\/p>/);
const firstParaLen = firstPMatch ? firstPMatch[1].length : 0;
checks.directAnswer = (firstParaLen >= 80 && firstParaLen <= 320) ? 5 : 0;
breakdown.push(`Respuesta directa: ${firstParaLen} chars (80-320) → ${checks.directAnswer}/5`);

// 10. key_takeaways block (5 pts)
checks.keyTakeaways = wpBody.content.includes('class="key-takeaways"') ? 5 : 0;
breakdown.push(`Key takeaways block: ${checks.keyTakeaways === 5 ? 'YES' : 'NO'} → ${checks.keyTakeaways}/5`);

// 11. FAQ + JSON-LD (5 pts)
checks.faq = (wpBody.content.includes('Preguntas frecuentes') && wpBody.content.includes('FAQPage')) ? 5 : 0;
breakdown.push(`FAQ + JSON-LD: ${checks.faq === 5 ? 'YES' : 'NO'} → ${checks.faq}/5`);

// 12. Frases prohibidas (10 pts)
const prohibited = ['en el mundo de','cuando se trata de','es importante señalar','cabe destacar','en la era digital','hoy en día','en el dinámico mundo','en última instancia','mascota'];
const lowerBody = bodyText.toLowerCase();
const violations = prohibited.filter(p => lowerBody.includes(p));
checks.prohibited = violations.length === 0 ? 10 : Math.max(0, 10 - violations.length * 3);
breakdown.push(`Frases prohibidas: ${violations.length === 0 ? 'CLEAN' : violations.join(' | ')} → ${checks.prohibited}/10`);

// 13. Mini-historias (5 pts) - heurística
const miniRegex = /\b[A-ZÁÉÍÓÚÑ][a-záéíóúñ]{2,}, (?:un|una|el|la|de) [a-záéíóúñ]+/g;
const miniMatches = (bodyText.match(miniRegex) || []).length;
checks.miniStories = miniMatches >= 2 ? 5 : (miniMatches === 1 ? 3 : 0);
breakdown.push(`Mini-historias detectadas: ~${miniMatches}/2 → ${checks.miniStories}/5`);

// 14. Sentence length avg < 25 (5 pts)
const sentences = bodyText.split(/[.!?]+/).filter(s => s.trim().length > 5);
const avgSent = sentences.length > 0 ? sentences.reduce((s, x) => s + x.split(/\s+/).length, 0) / sentences.length : 0;
checks.sentenceLen = avgSent <= 25 ? 5 : (avgSent <= 30 ? 3 : 0);
breakdown.push(`Avg sentence: ${avgSent.toFixed(1)} palabras (<25) → ${checks.sentenceLen}/5`);

// 15. Tags >= 5 (5 pts)
const tagsCount = (data.tags_list || []).length;
checks.tags = tagsCount >= 5 ? 5 : tagsCount;
breakdown.push(`Tags: ${tagsCount}/5 → ${checks.tags}/5`);

// 16. Fuentes consultadas: section + >= 3 sources (5 pts)
const fuentesSection = wpBody.content.match(/<section class="fuentes-consultadas">[\s\S]*?<\/section>/);
const fuentesCount = fuentesSection ? (fuentesSection[0].match(/<li>/g) || []).length : 0;
checks.fuentesConsultadas = fuentesCount >= 3 ? 5 : (fuentesCount > 0 ? Math.round((fuentesCount / 3) * 5) : 0);
breakdown.push(`Fuentes consultadas: ${fuentesCount}/3 → ${checks.fuentesConsultadas}/5`);

// 17. Tabla o data-box obligatoria (10 pts + HARD GATE)
const hasTable = /<table[^>]*>/i.test(wpBody.content) || /<dl[^>]*>/i.test(wpBody.content);
checks.tableData = hasTable ? 10 : 0;
breakdown.push(`Tabla/data-box: ${hasTable ? 'YES' : 'NO'} → ${checks.tableData}/10`);

// 18. H2 question-first ratio (5 pts) — solo H2 del cuerpo (excluye estructurales fijas)
const allH2 = wpBody.content.match(/<h2[^>]*>([\s\S]*?)<\/h2>/gi) || [];
const structuralH2 = /Conclusi[óo]n|Preguntas frecuentes|Fuentes consultadas/i;
const bodyH2 = allH2.filter(h => !structuralH2.test(h));
const h2Questions = bodyH2.filter(h => /<h2[^>]*>\s*¿/i.test(h)).length;
const h2Ratio = bodyH2.length > 0 ? h2Questions / bodyH2.length : 0;
checks.h2QuestionFirst = h2Ratio >= 0.6 ? 5 : (h2Ratio >= 0.4 ? 3 : (h2Ratio >= 0.2 ? 1 : 0));
breakdown.push(`H2 question-first (cuerpo): ${h2Questions}/${bodyH2.length} (${(h2Ratio*100).toFixed(0)}%) → ${checks.h2QuestionFirst}/5`);

const totalScore = Object.values(checks).reduce((s, v) => s + v, 0);
const breakdownStr = breakdown.join('\n');

// HARD GATE: tabla es obligatoria — las IAs priorizan tablas para citar
if (!hasTable) {
  throw new Error(`Quality gate FAIL — artículo sin <table> ni <dl> obligatoria:\n${breakdownStr}`);
}

// Quality Gate por score: si score < 70, lanza error → maneja Error Trigger
if (totalScore < 70) {
  throw new Error(`Quality gate failed (${totalScore}/120):\n${breakdownStr}`);
}

return {
  json: {
    ...data,
    quality_score: totalScore,
    quality_breakdown: breakdownStr
  }
};

// Internal Linker — valida URLs internas inventadas por GPT y/o las suplementa
// con enlaces reales desde la lista de posts publicados (bc-node-016).

const data = $input.item.json;
const wpBody = JSON.parse(data.wp_body_json);
const keyword = $('Leer Keywords Aprobadas').item.json.keyword || '';
const currentKwLower = keyword.toLowerCase().trim();

// Lista real de posts publicados (URL + keyword)
const publishedItems = $('Leer Posts Publicados').all();
const realPosts = publishedItems
  .filter(it => it.json.url_post && it.json.keyword)
  .map(it => ({
    keyword: String(it.json.keyword).toLowerCase().trim(),
    url: String(it.json.url_post).trim().replace(/\/+$/, '')
  }))
  .filter(p => p.keyword !== currentKwLower);

const realUrlSet = new Set(realPosts.map(p => p.url));
let body = wpBody.content;

function reEscape(s) { return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); }

// Paso 1: Strip URLs inválidas (alucinadas por GPT)
let strippedCount = 0;
body = body.replace(
  /<a\s+href="(https?:\/\/bigotescaninos\.com\/[^"]+)"[^>]*>([^<]+)<\/a>/gi,
  (match, url, anchor) => {
    const clean = url.replace(/\/+$/, '').split('#')[0];
    if (realUrlSet.has(clean)) return match;
    strippedCount++;
    return anchor;
  }
);

// Paso 2: Cuenta enlaces internos válidos restantes + ranges de TODOS los <a>
function collectLinkRanges(text) {
  const ranges = [];
  const re = /<a\b[^>]*>[^<]*<\/a>/gi;
  let m;
  while ((m = re.exec(text)) !== null) ranges.push([m.index, m.index + m[0].length]);
  return ranges;
}
let allLinkRanges = collectLinkRanges(body);
const currentInternalCount = (body.match(/href="https?:\/\/bigotescaninos\.com[^"]+"/g) || []).length;

// Paso 3: Si < 2 enlaces internos, inyecta desde la lista real
const targetMin = 2;
const usedUrls = new Set(
  (body.match(/href="(https?:\/\/bigotescaninos\.com[^"]+)"/g) || [])
    .map(s => s.match(/href="([^"]+)"/)[1].replace(/\/+$/, ''))
);
let injected = 0;
const needed = Math.max(0, targetMin - currentInternalCount);

if (needed > 0) {
  for (const post of realPosts) {
    if (injected >= needed) break;
    if (usedUrls.has(post.url)) continue;

    const kwRe = new RegExp('\\b' + reEscape(post.keyword) + '\\b', 'gi');
    let mm;
    let foundIdx = -1;
    let foundLen = 0;
    while ((mm = kwRe.exec(body)) !== null) {
      const inAnyLink = allLinkRanges.some(([s, e]) => mm.index >= s && mm.index < e);
      if (!inAnyLink) { foundIdx = mm.index; foundLen = mm[0].length; break; }
    }
    if (foundIdx === -1) continue;

    const matched = body.substring(foundIdx, foundIdx + foundLen);
    const replacement = '<a href="' + post.url + '">' + matched + '</a>';
    body = body.substring(0, foundIdx) + replacement + body.substring(foundIdx + foundLen);
    allLinkRanges = collectLinkRanges(body);
    usedUrls.add(post.url);
    injected++;
  }
}

wpBody.content = body;
const newWpBodyJson = JSON.stringify(wpBody);

return {
  json: {
    ...data,
    wp_body_json: newWpBodyJson,
    linker_stripped: strippedCount,
    linker_injected: injected,
    linker_total_internal: currentInternalCount + injected
  }
};

const wpResp = $input.item.json;
const original = $('Parsear JSON articulo').item.json;
const proposedSlug = original.slug || '';
const currentKeyword = $('Leer Keywords Aprobadas').first().json.keyword || '';

let posts = [];
if (Array.isArray(wpResp)) posts = wpResp;
else if (wpResp && wpResp.id) posts = [wpResp];

const conflict = posts.find(p => p && p.slug === proposedSlug);

if (conflict) {
  const title = (conflict.title && (conflict.title.rendered || conflict.title)) || '(post existente)';
  return [{ json: {
    ...original,
    cannibalism: true,
    similar_keyword: title,
    similar_url: conflict.link || '',
    similarity_pct: 100,
    match_reason: 'slug_wp_conflict',
    current_keyword: currentKeyword,
    proposed_slug: proposedSlug
  } }];
}

return [{ json: { ...original, cannibalism: false, slug_check_passed: true, proposed_slug: proposedSlug } }];
